const EQ_IMPORT_SOURCE: &str = "\
inductive Eq.{u} {A : Sort u} (a : A) : forall (b : A), Prop where
| refl : Eq.{u} a a
";

const NAT_IMPORT_SOURCE: &str = "\
inductive Nat : Type where
| zero : Nat
| succ : forall (n : Nat), Nat
";

fn main() {
    if let Err(err) = run() {
        eprintln!("{err}");
        std::process::exit(1);
    }
}

fn run() -> Result<(), String> {
    let args = std::env::args().skip(1).collect::<Vec<_>>();
    if args.is_empty() {
        return run_full();
    }

    match args[0].as_str() {
        "--package-lock-only" if args.len() == 1 => {
            let repo_root = repo_root()?;
            let proof_root = repo_root.join("proofs");
            write_package_lock_fixture(&proof_root)
        }
        "--build-module" => {
            let repo_root = repo_root()?;
            let options = parse_build_module_args(&args[1..])?;
            run_build_modules(&repo_root, &options)
        }
        "--build-modules" => {
            let repo_root = repo_root()?;
            let options = parse_build_modules_args(&args[1..])?;
            run_build_modules(&repo_root, &options)
        }
        "--build-modules-file" => {
            let repo_root = repo_root()?;
            let options = parse_build_modules_file_args(&repo_root, &args[1..])?;
            run_build_modules(&repo_root, &options)
        }
        "--promote-plan" => {
            let repo_root = repo_root()?;
            let options = parse_promote_plan_args(&repo_root, &args[1..])?;
            run_promote_plan(&repo_root, &options)
        }
        "--promote-materialize" => {
            let repo_root = repo_root()?;
            let options = parse_promote_materialize_args(&repo_root, &args[1..])?;
            run_promote_materialize(&repo_root, &options)
        }
        "--write-ai-index" => {
            let repo_root = repo_root()?;
            let proof_root = repo_root.join("proofs");
            let path = match args.get(1) {
                Some(path) => output_path(&repo_root, path),
                None => proof_root.join(AI_THEOREM_INDEX_PATH),
            };
            if args.len() > 2 {
                return Err(usage());
            }
            write_ai_theorem_index(&proof_root, &path)
        }
        "--write-replay" if args.len() == 3 => {
            let repo_root = repo_root()?;
            let proof_root = repo_root.join("proofs");
            write_focused_replay(&proof_root, &args[1], output_path(&repo_root, &args[2]))
        }
        "--help" | "-h" if args.len() == 1 => {
            println!("{}", usage());
            Ok(())
        }
        _ => run_verify(parse_verify_options(&args)?),
    }
}

fn output_path<P: AsRef<Path>>(repo_root: &Path, path: P) -> PathBuf {
    let path = path.as_ref();
    if path.is_absolute() {
        path.to_path_buf()
    } else {
        repo_root.join(path)
    }
}

fn usage() -> String {
    "\
usage:
  npa-proof-corpus
  npa-proof-corpus --package-lock-only
  npa-proof-corpus --build-module MODULE [--package-metadata|--metadata-once] [--failures-out PATH]
  npa-proof-corpus --build-modules MODULE ... [--package-metadata|--metadata-once] [--failures-out PATH]
  npa-proof-corpus --build-modules-file PATH [--package-metadata|--metadata-once] [--failures-out PATH]
  npa-proof-corpus --promote-plan CORPUS_MODULE --mathlib-root PATH --to-module Mathlib.* --out PATH
  npa-proof-corpus --promote-materialize PLAN --mathlib-root PATH [--dry-run|--apply] [--compat-alias none]
  npa-proof-corpus --verify [--module MODULE ...] [--changed-only] [--shard INDEX/TOTAL] [--failures-out PATH] [--verified-cache off|authoring|read-through]
  npa-proof-corpus --module MODULE [--shard INDEX/TOTAL] [--failures-out PATH] [--verified-cache off|authoring|read-through]
  npa-proof-corpus --changed-only [--shard INDEX/TOTAL] [--failures-out PATH] [--verified-cache off|authoring|read-through]
  npa-proof-corpus --write-ai-index [PATH]
  npa-proof-corpus --write-replay MODULE::DECL PATH

INDEX/TOTAL is zero-based, for example --shard 0/4.
--verified-cache defaults to off. authoring and read-through are only for --module or --changed-only.
--build-module and --build-modules default to authoring metadata only. --package-metadata also writes the package manifest and lock. --metadata-once is a compatibility alias.
"
    .to_owned()
}

fn parse_verify_options(args: &[String]) -> Result<VerifyOptions, String> {
    let mut options = VerifyOptions::default();
    let mut verified_cache_seen = false;
    let mut index = 0usize;
    while index < args.len() {
        match args[index].as_str() {
            "--verify" => {
                index += 1;
            }
            "--module" => {
                let module = args.get(index + 1).ok_or_else(usage)?.to_owned();
                options.modules.push(module);
                index += 2;
            }
            "--changed-only" => {
                options.changed_only = true;
                index += 1;
            }
            "--shard" => {
                let shard = args.get(index + 1).ok_or_else(usage)?;
                options.shard = Some(parse_shard(shard)?);
                index += 2;
            }
            "--failures-out" => {
                let path = args.get(index + 1).ok_or_else(usage).map(PathBuf::from)?;
                options.failures_out = Some(path);
                index += 2;
            }
            "--verified-cache" => {
                if verified_cache_seen {
                    return Err("duplicate --verified-cache option".to_owned());
                }
                let mode = args.get(index + 1).ok_or_else(usage)?;
                options.verified_cache = parse_verified_cache_mode(mode)?;
                verified_cache_seen = true;
                index += 2;
            }
            _ => return Err(usage()),
        }
    }
    if options.verified_cache != VerifiedCacheMode::Off
        && options.modules.is_empty()
        && !options.changed_only
    {
        return Err(
            "--verified-cache authoring/read-through is only supported with --module or --changed-only"
                .to_owned(),
        );
    }
    Ok(options)
}

fn parse_verified_cache_mode(value: &str) -> Result<VerifiedCacheMode, String> {
    match value {
        "off" => Ok(VerifiedCacheMode::Off),
        "authoring" => Ok(VerifiedCacheMode::Authoring),
        "read-through" => Ok(VerifiedCacheMode::ReadThrough),
        _ => Err(format!(
            "invalid --verified-cache mode {value:?}; expected off, authoring, or read-through"
        )),
    }
}

fn parse_shard(value: &str) -> Result<Shard, String> {
    let Some((index, total)) = value.split_once('/') else {
        return Err(format!("invalid shard {value:?}; expected INDEX/TOTAL"));
    };
    let index = index
        .parse::<usize>()
        .map_err(|_| format!("invalid shard index in {value:?}"))?;
    let total = total
        .parse::<usize>()
        .map_err(|_| format!("invalid shard total in {value:?}"))?;
    if total == 0 || index >= total {
        return Err(format!(
            "invalid shard {value:?}; require total > 0 and index < total"
        ));
    }
    Ok(Shard { index, total })
}

impl VerifiedCacheMode {
    fn as_str(self) -> &'static str {
        match self {
            VerifiedCacheMode::Off => "off",
            VerifiedCacheMode::Authoring => "authoring",
            VerifiedCacheMode::ReadThrough => "read-through",
        }
    }
}

impl VerifiedCacheLookupStatus {
    fn as_str(self) -> &'static str {
        match self {
            VerifiedCacheLookupStatus::Hit => "hit",
            VerifiedCacheLookupStatus::Miss => "miss",
            VerifiedCacheLookupStatus::SchemaMiss => "schema_miss",
            VerifiedCacheLookupStatus::Stale => "stale",
        }
    }
}

fn print_verified_module_status(
    module: &str,
    mode: VerifiedCacheMode,
    status: Option<VerifiedCacheLookupStatus>,
) {
    if mode == VerifiedCacheMode::Off {
        println!("verified {module}");
        return;
    }
    let status = status
        .expect("verified cache status should be reported when verified cache mode is enabled");
    println!(
        "verified {module} cache_status = \"{}\" cache_mode = \"{}\"",
        status.as_str(),
        mode.as_str()
    );
}

fn verify_selected_module_with_cache(
    repo_root: &Path,
    proof_root: &Path,
    cache: &mut VerifiedCorpusCache<'_>,
    module: &str,
    mode: VerifiedCacheMode,
) -> Result<Option<VerifiedCacheLookupStatus>, String> {
    if mode == VerifiedCacheMode::Off {
        cache.verify_module(module)?;
        return Ok(None);
    }

    let key_input = verified_cache_key_input_from_certificate(proof_root, module)?;
    let lookup = verified_cache_lookup(repo_root, &key_input)?;

    match mode {
        VerifiedCacheMode::Off => unreachable!(),
        VerifiedCacheMode::Authoring if lookup.status == VerifiedCacheLookupStatus::Hit => {
            Ok(Some(VerifiedCacheLookupStatus::Hit))
        }
        VerifiedCacheMode::Authoring => {
            let verified = cache.verify_module(module)?;
            write_verified_cache_entry(repo_root, key_input, &verified)?;
            Ok(Some(lookup.status))
        }
        VerifiedCacheMode::ReadThrough => {
            if matches!(
                lookup.status,
                VerifiedCacheLookupStatus::SchemaMiss | VerifiedCacheLookupStatus::Stale
            ) {
                discard_verified_cache_entry(&lookup.path)?;
            }
            let verified = cache.verify_module(module)?;
            let entry = verified_cache_entry_from_verified_module(key_input, &verified);
            let entry_json = verified_cache_entry_json(&entry);
            let mut status = lookup.status;
            if lookup.status == VerifiedCacheLookupStatus::Hit
                && lookup.source.as_deref() != Some(entry_json.as_str())
            {
                discard_verified_cache_entry(&lookup.path)?;
                status = VerifiedCacheLookupStatus::Stale;
            }
            write(
                verified_cache_entry_path(repo_root, &entry.cache_key),
                entry_json.as_bytes(),
            )?;
            Ok(Some(status))
        }
    }
}

fn run_verify(options: VerifyOptions) -> Result<(), String> {
    let repo_root = repo_root()?;
    let proof_root = repo_root.join("proofs");
    let mut targets = verify_targets(&repo_root, &options)?;
    targets.sort_by_key(|module| module_order(module).unwrap_or(usize::MAX));
    targets.dedup();
    if let Some(shard) = options.shard {
        targets = targets
            .into_iter()
            .enumerate()
            .filter_map(|(index, module)| (index % shard.total == shard.index).then_some(module))
            .collect();
    }

    if targets.is_empty() {
        println!("no proof corpus modules selected");
        return Ok(());
    }

    let mut cache = VerifiedCorpusCache::new(&proof_root);
    let mut failures = Vec::new();
    let mut verified_cache_hits = 0usize;
    for module in &targets {
        match verify_selected_module_with_cache(
            &repo_root,
            &proof_root,
            &mut cache,
            module,
            options.verified_cache,
        ) {
            Ok(status) => {
                if status == Some(VerifiedCacheLookupStatus::Hit) {
                    verified_cache_hits += 1;
                }
                print_verified_module_status(module, options.verified_cache, status);
            }
            Err(error) => {
                eprintln!("failed {module}: {error}");
                failures.push(VerifyFailure {
                    module: module.clone(),
                    error,
                });
            }
        }
    }

    if let Some(path) = options.failures_out {
        let path = if path.is_absolute() {
            path
        } else {
            repo_root.join(path)
        };
        write_failure_replay(&proof_root, &path, &failures)?;
    }

    if failures.is_empty() {
        if options.verified_cache == VerifiedCacheMode::Off {
            println!(
                "verified {} selected module(s), {} module(s) including dependency cache",
                targets.len(),
                cache.verified.len()
            );
        } else {
            println!(
                "verified {} selected module(s), {} module(s) including dependency cache, {} verified cache hit(s)",
                targets.len(),
                cache.verified.len(),
                verified_cache_hits
            );
        }
        Ok(())
    } else {
        Err(format!(
            "{} selected proof corpus module(s) failed",
            failures.len()
        ))
    }
}

fn parse_build_module_args(args: &[String]) -> Result<BuildOptions, String> {
    let options = parse_build_modules_args(args)?;
    if options.requested_modules.len() != 1 {
        return Err(usage());
    }
    Ok(options)
}

fn parse_build_modules_args(args: &[String]) -> Result<BuildOptions, String> {
    let mut options = BuildOptions::default();
    let mut index = 0usize;
    while index < args.len() {
        match args[index].as_str() {
            "--package-metadata" | "--metadata-once" => {
                options.package_metadata = true;
                index += 1;
            }
            "--failures-out" => {
                if options.failures_out.is_some() {
                    return Err("duplicate --failures-out option".to_owned());
                }
                let path = args.get(index + 1).ok_or_else(usage)?;
                options.failures_out = Some(PathBuf::from(path));
                index += 2;
            }
            module if module.starts_with("--") => return Err(usage()),
            module => {
                options.requested_modules.push(module.to_owned());
                index += 1;
            }
        }
    }
    if options.requested_modules.is_empty() {
        return Err(usage());
    }
    Ok(options)
}

fn parse_build_modules_file_args(
    repo_root: &Path,
    args: &[String],
) -> Result<BuildOptions, String> {
    let file = args.first().ok_or_else(usage)?;
    let mut options = parse_build_metadata_options(&args[1..])?;
    options.requested_modules = parse_build_modules_file(&output_path(repo_root, file))?;
    Ok(options)
}

fn parse_build_metadata_options(args: &[String]) -> Result<BuildOptions, String> {
    let mut options = BuildOptions::default();
    let mut index = 0usize;
    while index < args.len() {
        match args[index].as_str() {
            "--package-metadata" | "--metadata-once" => {
                options.package_metadata = true;
                index += 1;
            }
            "--failures-out" => {
                if options.failures_out.is_some() {
                    return Err("duplicate --failures-out option".to_owned());
                }
                let path = args.get(index + 1).ok_or_else(usage)?;
                options.failures_out = Some(PathBuf::from(path));
                index += 2;
            }
            _ => return Err(usage()),
        }
    }
    Ok(options)
}

fn parse_build_modules_file(path: &Path) -> Result<Vec<String>, String> {
    let source = fs::read_to_string(path).map_err(|err| {
        format!(
            "failed to read build modules file {}: {err}",
            path.display()
        )
    })?;
    parse_build_modules_file_contents(&source)
        .map_err(|err| format!("invalid build modules file {}: {err}", path.display()))
}

fn parse_build_modules_file_contents(source: &str) -> Result<Vec<String>, String> {
    let mut modules = Vec::new();
    for (index, line) in source.lines().enumerate() {
        let module = line
            .split_once('#')
            .map(|(module, _)| module)
            .unwrap_or(line)
            .trim();
        if module.is_empty() {
            continue;
        }
        if module.split_whitespace().count() != 1 {
            return Err(format!(
                "line {} must contain exactly one module name",
                index + 1
            ));
        }
        modules.push(module.to_owned());
    }
    if modules.is_empty() {
        return Err("no proof corpus modules requested".to_owned());
    }
    Ok(modules)
}

fn parse_promote_plan_args(
    repo_root: &Path,
    args: &[String],
) -> Result<PromotePlanOptions, String> {
    let corpus_module = args
        .first()
        .ok_or_else(|| "promote-plan error: missing_corpus_module".to_owned())?
        .to_owned();
    if corpus_module.starts_with("--") {
        return Err("promote-plan error: missing_corpus_module".to_owned());
    }

    let mut mathlib_root_arg = None;
    let mut target_module = None;
    let mut out_arg = None;
    let mut index = 1usize;
    while index < args.len() {
        match args[index].as_str() {
            "--mathlib-root" => {
                if mathlib_root_arg.is_some() {
                    return Err("promote-plan error: duplicate_option --mathlib-root".to_owned());
                }
                let path = args
                    .get(index + 1)
                    .ok_or_else(|| "promote-plan error: missing_value --mathlib-root".to_owned())?;
                mathlib_root_arg = Some(PathBuf::from(path));
                index += 2;
            }
            "--to-module" => {
                if target_module.is_some() {
                    return Err("promote-plan error: duplicate_option --to-module".to_owned());
                }
                let module = args
                    .get(index + 1)
                    .ok_or_else(|| "promote-plan error: missing_value --to-module".to_owned())?;
                validate_mathlib_module(module)?;
                target_module = Some(module.to_owned());
                index += 2;
            }
            "--out" => {
                if out_arg.is_some() {
                    return Err("promote-plan error: duplicate_option --out".to_owned());
                }
                let path = args
                    .get(index + 1)
                    .ok_or_else(|| "promote-plan error: missing_value --out".to_owned())?;
                out_arg = Some(PathBuf::from(path));
                index += 2;
            }
            option if option.starts_with("--") => {
                return Err(format!("promote-plan error: unknown_option {option}"));
            }
            value => {
                return Err(format!("promote-plan error: unexpected_argument {value}"));
            }
        }
    }

    let mathlib_root_arg = mathlib_root_arg
        .ok_or_else(|| "promote-plan error: missing_option --mathlib-root".to_owned())?;
    let target_module =
        target_module.ok_or_else(|| "promote-plan error: missing_option --to-module".to_owned())?;
    let out_arg = out_arg.ok_or_else(|| "promote-plan error: missing_option --out".to_owned())?;

    Ok(PromotePlanOptions {
        corpus_module,
        mathlib_root: output_path(repo_root, &mathlib_root_arg),
        mathlib_root_arg,
        target_module,
        out: output_path(repo_root, &out_arg),
        out_arg,
    })
}

fn validate_mathlib_module(module: &str) -> Result<(), String> {
    validate_mathlib_module_for("promote-plan", module)
}

fn validate_mathlib_module_for(command: &str, module: &str) -> Result<(), String> {
    if !module.starts_with("Mathlib.") || module == "Mathlib." {
        return Err(format!(
            "{command} error: invalid_target_module {module}; expected Mathlib.*"
        ));
    }
    for component in module.split('.') {
        if component.is_empty() {
            return Err(format!(
                "{command} error: invalid_target_module {module}; empty component"
            ));
        }
        let mut chars = component.chars();
        let first = chars.next().unwrap_or_default();
        if !(first.is_ascii_alphabetic() || first == '_') {
            return Err(format!(
                "{command} error: invalid_target_module {module}; bad component {component}"
            ));
        }
        if chars.any(|ch| !(ch.is_ascii_alphanumeric() || ch == '_')) {
            return Err(format!(
                "{command} error: invalid_target_module {module}; bad component {component}"
            ));
        }
    }
    Ok(())
}

fn parse_promote_materialize_args(
    repo_root: &Path,
    args: &[String],
) -> Result<PromoteMaterializeOptions, String> {
    let plan_arg = args
        .first()
        .ok_or_else(|| "promote-materialize error: missing_plan".to_owned())?;
    if plan_arg.starts_with("--") {
        return Err("promote-materialize error: missing_plan".to_owned());
    }

    let mut mathlib_root_arg = None;
    let mut mode = PromoteMaterializeMode::DryRun;
    let mut mode_seen = false;
    let mut compat_alias = None;
    let mut index = 1usize;
    while index < args.len() {
        match args[index].as_str() {
            "--mathlib-root" => {
                if mathlib_root_arg.is_some() {
                    return Err(
                        "promote-materialize error: duplicate_option --mathlib-root".to_owned()
                    );
                }
                let path = args.get(index + 1).ok_or_else(|| {
                    "promote-materialize error: missing_value --mathlib-root".to_owned()
                })?;
                mathlib_root_arg = Some(PathBuf::from(path));
                index += 2;
            }
            "--dry-run" => {
                if mode_seen {
                    return Err("promote-materialize error: duplicate_mode".to_owned());
                }
                mode = PromoteMaterializeMode::DryRun;
                mode_seen = true;
                index += 1;
            }
            "--apply" => {
                if mode_seen {
                    return Err("promote-materialize error: duplicate_mode".to_owned());
                }
                mode = PromoteMaterializeMode::Apply;
                mode_seen = true;
                index += 1;
            }
            "--compat-alias" => {
                if compat_alias.is_some() {
                    return Err(
                        "promote-materialize error: duplicate_option --compat-alias".to_owned()
                    );
                }
                let value = args.get(index + 1).ok_or_else(|| {
                    "promote-materialize error: missing_value --compat-alias".to_owned()
                })?;
                compat_alias = Some(parse_compat_alias_decision(value)?);
                index += 2;
            }
            option if option.starts_with("--") => {
                return Err(format!(
                    "promote-materialize error: unknown_option {option}"
                ));
            }
            value => {
                return Err(format!(
                    "promote-materialize error: unexpected_argument {value}"
                ));
            }
        }
    }

    let mathlib_root_arg = mathlib_root_arg
        .ok_or_else(|| "promote-materialize error: missing_option --mathlib-root".to_owned())?;

    Ok(PromoteMaterializeOptions {
        plan_arg: PathBuf::from(plan_arg.as_str()),
        plan: output_path(repo_root, plan_arg.as_str()),
        mathlib_root: output_path(repo_root, &mathlib_root_arg),
        mathlib_root_arg,
        mode,
        compat_alias,
    })
}

fn parse_compat_alias_decision(value: &str) -> Result<CompatibilityAliasDecision, String> {
    match value {
        "none" => Ok(CompatibilityAliasDecision::None),
        other => Err(format!(
            "promote-materialize error: invalid_compat_alias {other}; expected none"
        )),
    }
}

fn run_build_modules(repo_root: &Path, options: &BuildOptions) -> Result<(), String> {
    let proof_root = repo_root.join("proofs");
    let mut failures = Vec::new();
    let result = run_build_modules_inner(&proof_root, options, &mut failures);
    if let Some(path) = &options.failures_out {
        write_failure_replay(&proof_root, &output_path(repo_root, path), &failures)?;
    }
    result
}

fn run_build_modules_inner(
    proof_root: &Path,
    options: &BuildOptions,
    failures: &mut Vec<VerifyFailure>,
) -> Result<(), String> {
    let selected_modules = match build_batch_selection(&options.requested_modules) {
        Ok(selected) => selected,
        Err(error) => {
            failures.push(VerifyFailure {
                module: first_unknown_requested_module(&options.requested_modules)
                    .unwrap_or_default(),
                error: error.clone(),
            });
            return Err(error);
        }
    };
    fs::create_dir_all(proof_root).map_err(|err| {
        record_build_failure(
            failures,
            "",
            format!("failed to create {}: {err}", proof_root.display()),
        )
    })?;

    let external_imports = generated_external_std_imports()
        .map_err(|error| record_build_failure(failures, "", error))?;
    write_external_import_artifacts(proof_root, &external_imports)
        .map_err(|error| record_build_failure(failures, "", error))?;

    let mut cache = BuiltCorpusCache::new(proof_root, external_imports);
    for config in &selected_modules {
        if let Err(error) = cache.build_module(config.module) {
            failures.push(VerifyFailure {
                module: config.module.to_owned(),
                error: error.clone(),
            });
            return Err(error);
        }
    }

    if options.package_metadata {
        let existing_metas = existing_module_metas(proof_root)
            .map_err(|error| record_build_failure(failures, "", error))?;
        write_package_metadata_once(proof_root, existing_metas, &cache)
            .map_err(|error| record_build_failure(failures, "", error))?;
    } else {
        write_authoring_metadata(proof_root)
            .map_err(|error| record_build_failure(failures, "", error))?;
    }

    if options.requested_modules.len() == 1 {
        println!(
            "built {} ({} module(s) including import closure)",
            options.requested_modules[0],
            cache.built.len()
        );
    } else {
        println!(
            "built {} requested module(s), {} module(s) including import closure",
            options.requested_modules.len(),
            cache.built.len()
        );
    }
    Ok(())
}

fn record_build_failure(
    failures: &mut Vec<VerifyFailure>,
    module: impl Into<String>,
    error: String,
) -> String {
    failures.push(VerifyFailure {
        module: module.into(),
        error: error.clone(),
    });
    error
}

fn first_unknown_requested_module(requested_modules: &[String]) -> Option<String> {
    requested_modules
        .iter()
        .find(|module| module_config(module).is_none())
        .cloned()
}

fn write_authoring_metadata(proof_root: &Path) -> Result<(), String> {
    write_ai_theorem_index(proof_root, &proof_root.join(AI_THEOREM_INDEX_PATH))
}

fn write_package_metadata_once(
    proof_root: &Path,
    existing_metas: BTreeMap<String, ModuleMeta>,
    cache: &BuiltCorpusCache<'_>,
) -> Result<(), String> {
    let built_metas = cache
        .built
        .iter()
        .map(|(module, generated)| (module.clone(), ModuleMeta::from(generated)))
        .collect::<BTreeMap<_, _>>();
    let module_metas = batch_module_metas(existing_metas, built_metas)?;
    let manifest = manifest_toml(&module_metas);
    let package_manifest = package_manifest_toml(&module_metas, &cache.external_imports)?;
    write(proof_root.join(MANIFEST_PATH), manifest.as_bytes())?;
    write(
        proof_root.join(PACKAGE_MANIFEST_PATH),
        package_manifest.as_bytes(),
    )?;
    write_package_lock_fixture(proof_root)?;
    write_ai_theorem_index(proof_root, &proof_root.join(AI_THEOREM_INDEX_PATH))?;
    Ok(())
}

fn existing_module_metas(proof_root: &Path) -> Result<BTreeMap<String, ModuleMeta>, String> {
    let mut metas = package_manifest_module_metas(proof_root)?;
    for config in MODULES {
        if metas.contains_key(config.module) {
            continue;
        }
        if let Some(meta) = checked_in_module_meta(proof_root, config)? {
            metas.insert(config.module.to_owned(), meta);
        }
    }
    Ok(metas)
}

fn checked_in_module_meta(
    proof_root: &Path,
    config: &'static ModuleArtifact,
) -> Result<Option<ModuleMeta>, String> {
    let path = proof_root.join(config.meta_path);
    let source = match fs::read_to_string(&path) {
        Ok(source) => source,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => return Err(format!("failed to read {}: {err}", config.meta_path)),
    };
    module_meta_from_meta_json(config, &source).map(Some)
}

fn module_meta_from_meta_json(
    config: &'static ModuleArtifact,
    source: &str,
) -> Result<ModuleMeta, String> {
    let module = top_level_json_string_field(source, "module")
        .ok_or_else(|| format!("{} missing module field", config.meta_path))?;
    if module != config.module {
        return Err(format!(
            "{} has module {module:?}, expected {:?}",
            config.meta_path, config.module
        ));
    }
    let source_path = top_level_json_string_field(source, "source")
        .ok_or_else(|| format!("{} missing source field", config.meta_path))?;
    if source_path != config.source_path {
        return Err(format!(
            "{} has source {source_path:?}, expected {:?}",
            config.meta_path, config.source_path
        ));
    }
    let certificate_path = top_level_json_string_field(source, "certificate")
        .ok_or_else(|| format!("{} missing certificate field", config.meta_path))?;
    if certificate_path != config.certificate_path {
        return Err(format!(
            "{} has certificate {certificate_path:?}, expected {:?}",
            config.meta_path, config.certificate_path
        ));
    }

    Ok(ModuleMeta {
        config,
        source_sha256: required_json_string_field(source, config.meta_path, "source_sha256")?,
        certificate_file_sha256: required_json_string_field(
            source,
            config.meta_path,
            "certificate_file_sha256",
        )?,
        export_hash: required_json_string_field(source, config.meta_path, "export_hash")?,
        axiom_report_hash: required_json_string_field(
            source,
            config.meta_path,
            "axiom_report_hash",
        )?,
        certificate_hash: required_json_string_field(source, config.meta_path, "certificate_hash")?,
        axioms: top_level_json_string_array_field(source, "axioms")
            .ok_or_else(|| format!("{} missing axioms field", config.meta_path))?,
    })
}

fn required_json_string_field(source: &str, path: &str, field: &str) -> Result<String, String> {
    top_level_json_string_field(source, field)
        .ok_or_else(|| format!("{path} missing {field} field"))
}

fn batch_module_metas(
    mut existing_metas: BTreeMap<String, ModuleMeta>,
    mut built_metas: BTreeMap<String, ModuleMeta>,
) -> Result<Vec<ModuleMeta>, String> {
    let mut module_metas = Vec::with_capacity(MODULES.len());
    for module_config in MODULES {
        let meta = if let Some(generated) = built_metas.remove(module_config.module) {
            generated
        } else {
            existing_metas
                .remove(module_config.module)
                .ok_or_else(|| format!("missing existing metadata for {}", module_config.module))?
        };
        module_metas.push(meta);
    }
    Ok(module_metas)
}

fn build_batch_selection(
    requested_modules: &[String],
) -> Result<Vec<&'static ModuleArtifact>, String> {
    if requested_modules.is_empty() {
        return Err("no proof corpus modules requested".to_owned());
    }
    let mut selected = BTreeSet::new();
    for module in requested_modules {
        let config =
            module_config(module).ok_or_else(|| format!("unknown proof corpus module {module}"))?;
        collect_build_closure(config.module, &mut selected)?;
    }
    let mut selected = selected
        .into_iter()
        .map(|module| module_config(module).expect("selected module must exist"))
        .collect::<Vec<_>>();
    selected.sort_by_key(|config| module_order(config.module).unwrap_or(usize::MAX));
    Ok(selected)
}

fn collect_build_closure(
    module: &str,
    selected: &mut BTreeSet<&'static str>,
) -> Result<(), String> {
    if external_import_plan(module).is_some() {
        return Ok(());
    }
    if selected.contains(module) {
        return Ok(());
    }
    let config =
        module_config(module).ok_or_else(|| format!("unknown proof corpus module {module}"))?;
    for import in config.imports.iter().chain(source_imports(config)) {
        if external_import_plan(import).is_none() {
            collect_build_closure(import, selected)?;
        }
    }
    selected.insert(config.module);
    Ok(())
}

fn verify_targets(repo_root: &Path, options: &VerifyOptions) -> Result<Vec<String>, String> {
    let mut targets = Vec::new();
    if options.changed_only {
        targets.extend(changed_modules(repo_root)?);
    }
    targets.extend(options.modules.iter().cloned());
    if targets.is_empty() && !options.changed_only {
        targets.extend(MODULES.iter().map(|module| module.module.to_owned()));
    }
    for module in &targets {
        if module_config(module).is_none() {
            return Err(format!("unknown proof corpus module {module}"));
        }
    }
    Ok(targets)
}

fn changed_modules(repo_root: &Path) -> Result<Vec<String>, String> {
    let output = Command::new("git")
        .arg("status")
        .arg("--porcelain")
        .arg("--")
        .arg("proofs")
        .current_dir(repo_root)
        .output()
        .map_err(|err| format!("failed to run git status for changed proof corpus files: {err}"))?;
    if !output.status.success() {
        return Err(format!(
            "git status for changed proof corpus files failed: {}",
            String::from_utf8_lossy(&output.stderr)
        ));
    }
    let stdout = String::from_utf8_lossy(&output.stdout);
    let mut modules = BTreeSet::new();
    let mut all_modules = false;
    for line in stdout.lines() {
        if line.len() < 4 {
            continue;
        }
        let path = line[3..]
            .rsplit_once(" -> ")
            .map(|(_, new_path)| new_path)
            .unwrap_or(&line[3..]);
        let path = path.trim();
        let Some(package_path) = path.strip_prefix("proofs/") else {
            continue;
        };
        if matches!(
            package_path,
            MANIFEST_PATH | PACKAGE_MANIFEST_PATH | PACKAGE_LOCK_PATH
        ) {
            all_modules = true;
            continue;
        }
        if let Some(module) = module_for_package_path(package_path) {
            modules.insert(module.to_owned());
        }
    }
    if all_modules {
        Ok(MODULES
            .iter()
            .map(|module| module.module.to_owned())
            .collect())
    } else {
        Ok(modules.into_iter().collect())
    }
}

impl<'a> VerifiedCorpusCache<'a> {
    fn new(proof_root: &'a Path) -> Self {
        Self {
            proof_root,
            session: npa_cert::VerifierSession::new(),
            verified: BTreeMap::new(),
        }
    }

    fn verify_module(&mut self, module: &str) -> Result<npa_cert::VerifiedModule, String> {
        if let Some(verified) = self.verified.get(module) {
            return Ok(verified.clone());
        }

        if let Some(plan) = external_import_plan(module) {
            let verified = self.verify_certificate_at(
                module,
                plan.certificate_path,
                &npa_cert::AxiomPolicy::normal(),
            )?;
            self.verified.insert(module.to_owned(), verified.clone());
            return Ok(verified);
        }

        let config =
            module_config(module).ok_or_else(|| format!("unknown proof corpus module {module}"))?;
        for import in source_imports(config) {
            self.verify_module(import)?;
        }
        let policy = axiom_policy_for_module(module);
        let verified = self.verify_certificate_at(module, config.certificate_path, &policy)?;
        validate_verified_module(config, &verified)?;
        self.verified.insert(module.to_owned(), verified.clone());
        Ok(verified)
    }

    fn verify_certificate_at(
        &mut self,
        module: &str,
        certificate_path: &str,
        policy: &npa_cert::AxiomPolicy,
    ) -> Result<npa_cert::VerifiedModule, String> {
        let bytes = fs::read(self.proof_root.join(certificate_path))
            .map_err(|err| format!("failed to read {certificate_path}: {err}"))?;
        let verified = npa_cert::verify_module_cert(&bytes, &mut self.session, policy)
            .map_err(|err| format!("failed to verify {certificate_path}: {err:?}"))?;
        let actual = verified.module().as_dotted();
        if actual != module {
            return Err(format!(
                "certificate {certificate_path} is for module {actual}, expected {module}"
            ));
        }
        Ok(verified)
    }
}

impl<'a> BuiltCorpusCache<'a> {
    fn new(proof_root: &'a Path, external_imports: Vec<GeneratedExternalImport>) -> Self {
        Self {
            proof_root,
            external_imports,
            built: BTreeMap::new(),
        }
    }

    fn build_module(&mut self, module: &str) -> Result<(), String> {
        if self.built.contains_key(module) {
            return Ok(());
        }
        if external_import_plan(module).is_some() {
            return Ok(());
        }

        let config =
            module_config(module).ok_or_else(|| format!("unknown proof corpus module {module}"))?;
        let mut internal_imports = BTreeSet::new();
        for import in config.imports.iter().chain(source_imports(config)) {
            if external_import_plan(import).is_some() {
                continue;
            }
            internal_imports.insert(*import);
        }
        for import in internal_imports {
            self.build_module(import)?;
        }

        let mut verified_modules = Vec::with_capacity(config.imports.len());
        for import in config.imports {
            verified_modules.push(self.verified_module_for(import)?);
        }
        let mut source_interfaces = Vec::with_capacity(source_imports(config).len());
        for import in source_imports(config) {
            source_interfaces.push(self.source_interface_for(import)?);
        }

        let generated = build_and_write_module(
            self.proof_root,
            config,
            &verified_modules,
            &source_interfaces,
        )?;
        self.built.insert(module.to_owned(), generated);
        println!("built {module}");
        Ok(())
    }

    fn verified_module_for(&self, module: &str) -> Result<npa_cert::VerifiedModule, String> {
        if let Ok(import) = generated_external_import(&self.external_imports, module) {
            return Ok(import.verified_module.clone());
        }
        self.built
            .get(module)
            .map(|generated| generated.verified_module.clone())
            .ok_or_else(|| format!("missing built proof corpus dependency {module}"))
    }

    fn source_interface_for(
        &self,
        module: &str,
    ) -> Result<npa_frontend::HumanImportedSourceInterface, String> {
        if let Ok(import) = generated_external_import(&self.external_imports, module) {
            return Ok(import.source_interface.clone());
        }
        self.built
            .get(module)
            .map(|generated| generated.source_interface.clone())
            .ok_or_else(|| {
                format!("missing built proof corpus dependency source interface {module}")
            })
    }
}

impl From<&GeneratedModule> for ModuleMeta {
    fn from(module: &GeneratedModule) -> Self {
        Self {
            config: module.config,
            source_sha256: module.source_sha256.clone(),
            certificate_file_sha256: module.certificate_file_sha256.clone(),
            export_hash: module.export_hash.clone(),
            axiom_report_hash: module.axiom_report_hash.clone(),
            certificate_hash: module.certificate_hash.clone(),
            axioms: module.axioms.clone(),
        }
    }
}

fn package_manifest_module_metas(
    proof_root: &Path,
) -> Result<BTreeMap<String, ModuleMeta>, String> {
    let source = fs::read_to_string(proof_root.join(PACKAGE_MANIFEST_PATH))
        .map_err(|err| format!("failed to read {PACKAGE_MANIFEST_PATH}: {err}"))?;
    let validated = npa_package::parse_and_validate_manifest_str(&source)
        .map_err(|err| format!("failed to parse {PACKAGE_MANIFEST_PATH}: {err:?}"))?;
    let mut metas = BTreeMap::new();
    for module in &validated.manifest().modules {
        let module_name = module.module.as_dotted();
        let Some(config) = module_config(&module_name) else {
            continue;
        };
        validate_package_module_matches_config(module, config)?;
        metas.insert(module_name, module_meta_from_package_module(module, config));
    }
    Ok(metas)
}

fn validate_package_module_matches_config(
    module: &npa_package::PackageModule,
    config: &ModuleArtifact,
) -> Result<(), String> {
    let expected = [
        ("source", module.source.as_str(), config.source_path),
        (
            "certificate",
            module.certificate.as_str(),
            config.certificate_path,
        ),
    ];
    for (field, actual, expected) in expected {
        if actual != expected {
            return Err(format!(
                "{PACKAGE_MANIFEST_PATH} module {} has {field} {actual:?}, expected {expected:?}",
                config.module
            ));
        }
    }
    if module.meta.as_ref().map(|path| path.as_str()) != Some(config.meta_path) {
        return Err(format!(
            "{PACKAGE_MANIFEST_PATH} module {} has stale meta path",
            config.module
        ));
    }
    if module.replay.as_ref().map(|path| path.as_str()) != Some(config.replay_path) {
        return Err(format!(
            "{PACKAGE_MANIFEST_PATH} module {} has stale replay path",
            config.module
        ));
    }
    Ok(())
}

fn module_meta_from_package_module(
    module: &npa_package::PackageModule,
    config: &'static ModuleArtifact,
) -> ModuleMeta {
    ModuleMeta {
        config,
        source_sha256: npa_package::format_package_hash(&module.expected_source_hash),
        certificate_file_sha256: npa_package::format_package_hash(
            &module.expected_certificate_file_hash,
        ),
        export_hash: npa_package::format_package_hash(&module.expected_export_hash),
        axiom_report_hash: npa_package::format_package_hash(&module.expected_axiom_report_hash),
        certificate_hash: npa_package::format_package_hash(&module.expected_certificate_hash),
        axioms: module
            .axioms
            .as_deref()
            .unwrap_or_default()
            .iter()
            .map(|axiom| axiom.as_dotted())
            .collect(),
    }
}

fn validate_verified_module(
    config: &ModuleArtifact,
    verified: &npa_cert::VerifiedModule,
) -> Result<(), String> {
    let axioms = verified
        .axiom_report()
        .module_axioms
        .iter()
        .map(|axiom| verified.name_table()[axiom.name].as_dotted())
        .collect::<Vec<_>>();
    let expected_axioms = config
        .expected_axioms
        .iter()
        .map(|axiom| (*axiom).to_owned())
        .collect::<Vec<_>>();
    if axioms != expected_axioms {
        return Err(format!(
            "checked-in AI proof corpus module {} has axioms {:?}, expected {:?}",
            config.module, axioms, expected_axioms
        ));
    }
    let expected_features = expected_core_features_for_module(config.module);
    if verified.axiom_report().core_features != expected_features {
        return Err(format!(
            "checked-in AI proof corpus module {} has core features {:?}, expected {:?}",
            config.module,
            verified.axiom_report().core_features,
            expected_features
        ));
    }
    Ok(())
}

fn write_failure_replay(
    proof_root: &Path,
    path: &Path,
    failures: &[VerifyFailure],
) -> Result<(), String> {
    let entries = failures
        .iter()
        .map(|failure| {
            let replay_path = module_config(&failure.module)
                .map(|module| module.replay_path)
                .unwrap_or("");
            format!(
                "    {{ \"module\": \"{}\", \"replay\": \"{}\", \"error\": \"{}\" }}",
                json_escape(&failure.module),
                json_escape(replay_path),
                json_escape(&failure.error)
            )
        })
        .collect::<Vec<_>>()
        .join(",\n");
    let body = format!(
        "\
{{
  \"schema\": \"npa-proof-corpus-failure-replay.v1\",
  \"trusted\": false,
  \"failed_modules\": [
{}
  ]
}}
",
        entries
    );
    let output = if path.is_absolute() {
        path.to_path_buf()
    } else {
        proof_root.join(path)
    };
    write(output, body.as_bytes())
}

fn write_ai_theorem_index(_proof_root: &Path, path: &Path) -> Result<(), String> {
    let entries = MODULES
        .iter()
        .flat_map(|module| {
            module.theorems.iter().map(move |theorem| {
                let replay_spec = format!("{}::{}", module.module, theorem.name);
                format!(
                    "    {{ \"module\": \"{}\", \"theorem\": \"{}\", \"statement\": \"{}\", \"statement_sha256\": \"{}\", \"imports\": [{}], \"certificate\": \"{}\", \"replay\": \"{}\", \"focused_replay_spec\": \"{}\" }}",
                    json_escape(module.module),
                    json_escape(theorem.name),
                    json_escape(theorem.statement),
                    tagged_sha256(theorem.statement.as_bytes()),
                    quoted_items(source_imports(module)),
                    json_escape(module.certificate_path),
                    json_escape(module.replay_path),
                    json_escape(&replay_spec)
                )
            })
        })
        .collect::<Vec<_>>()
        .join(",\n");
    let body = format!(
        "\
{{
  \"schema\": \"npa.ai.theorem_index.v1\",
  \"package\": \"{}\",
  \"version\": \"{}\",
  \"trusted\": false,
  \"entry_count\": {},
  \"entries\": [
{}
  ]
}}
",
        PROOF_CORPUS_PACKAGE,
        PROOF_CORPUS_VERSION,
        MODULES
            .iter()
            .map(|module| module.theorems.len())
            .sum::<usize>(),
        entries
    );
    write(path.to_path_buf(), body.as_bytes())?;
    println!("wrote {}", path.display());
    Ok(())
}

fn write_focused_replay(proof_root: &Path, spec: &str, path: PathBuf) -> Result<(), String> {
    let (module_name, declaration) = spec
        .split_once("::")
        .ok_or_else(|| format!("invalid replay spec {spec:?}; expected MODULE::DECL"))?;
    let config = module_config(module_name)
        .ok_or_else(|| format!("unknown proof corpus module {module_name}"))?;
    let step = focused_replay_step(proof_root, config, declaration)?;
    let body = format!(
        "\
{{
  \"schema\": \"npa-ai-proof-replay-v0.1\",
  \"module\": \"{}\",
  \"trusted\": false,
  \"profile\": \"focused_explicit_term_source_certificate_handoff\",
  \"steps\": [
{}
  ],
  \"acceptance\": {{
    \"required\": [\"decode_module_cert\", \"verify_module_cert\"],
    \"accepted_artifact\": \"{}\"
  }}
}}
",
        config.module, step, config.certificate_path
    );
    write(path, body.as_bytes())
}

fn focused_replay_step(
    proof_root: &Path,
    config: &ModuleArtifact,
    declaration: &str,
) -> Result<String, String> {
    if uses_checked_in_source(config.module) {
        let source = fs::read_to_string(proof_root.join(config.source_path))
            .map_err(|err| format!("failed to read {}: {err}", config.source_path))?;
        if let Some((_, kind, term)) = source_replay_steps(&source)
            .into_iter()
            .find(|(name, _, _)| name == declaration)
        {
            return Ok(replay_step_json(declaration, kind, &term));
        }
    }
    if let Some(inductive) = config
        .inductives
        .iter()
        .find(|inductive| inductive.name == declaration)
    {
        return Ok(replay_step_json(
            declaration,
            "inductive_decl",
            &inductive_replay_term(inductive),
        ));
    }
    if let Some(definition) = config
        .definitions
        .iter()
        .find(|definition| definition.name == declaration)
    {
        return Ok(replay_step_json(
            declaration,
            "explicit_def_value",
            definition.value,
        ));
    }
    if let Some(theorem) = config
        .theorems
        .iter()
        .find(|theorem| theorem.name == declaration)
    {
        return Ok(replay_step_json(
            declaration,
            "explicit_term",
            theorem.proof,
        ));
    }
    Err(format!(
        "module {} has no replay declaration {declaration}",
        config.module
    ))
}

fn module_config(module: &str) -> Option<&'static ModuleArtifact> {
    MODULES
        .iter()
        .copied()
        .find(|config| config.module == module)
}

fn module_order(module: &str) -> Option<usize> {
    MODULES.iter().position(|config| config.module == module)
}

fn module_for_package_path(path: &str) -> Option<&'static str> {
    MODULES
        .iter()
        .find(|module| {
            path == module.source_path
                || path == module.certificate_path
                || path == module.meta_path
                || path == module.replay_path
        })
        .map(|module| module.module)
}

